const body = $input.first().json.body || {};
const batchRaw = Number(body.batch_size);
const batchSize = Number.isFinite(batchRaw) && batchRaw > 0
  ? Math.min(Math.trunc(batchRaw), 100)
  : 5;

return [{
  json: {
    trigger: 'webhook',
    batch_size: batchSize
  }
}];

return items.map((item, index) => {
  const j = item.json || {};
  const shortlist = Array.isArray(j.shortlist_json) ? j.shortlist_json : [];

  const ruleTopScoreRaw = Number(j.rule_top_score);
  const ruleTopScore = Number.isFinite(ruleTopScoreRaw) ? ruleTopScoreRaw : 0;

  const highThreshold = 20;
  const mediumThreshold = 10;

  const shortlistText = shortlist.length
    ? shortlist.map((c, idx) => {
        const reasons = Array.isArray(c.reasons) ? c.reasons.join(', ') : '';
        return `${idx + 1}. id=${c.category_id}, code=${c.category_code}, name=${c.category_name}, score=${c.score}, reasons=${reasons}`;
      }).join('\n')
    : 'EMPTY';

  const ruleTopCategoryId = j.rule_top_category_id !== undefined && j.rule_top_category_id !== null && j.rule_top_category_id !== ''
    ? Number(j.rule_top_category_id)
    : null;

  const ruleHint = ruleTopCategoryId
    ? `Rule engine suggests category_id=${ruleTopCategoryId} as top candidate with score=${ruleTopScore}.`
    : 'Rule engine has no strong suggestion.';

  let shortlistPolicyText = '';
  if (!shortlist.length || ruleTopScore < mediumThreshold) {
    shortlistPolicyText = `
Политика выбора:
- Shortlist пустой или низкоуверенный.
- Рассматривай shortlist как слабую подсказку, а не как ограничение.
- Если видишь более подходящую категорию вне shortlist, можешь выбрать её.
- Если уверенно выбрать нельзя, верни category_id = null и в объяснении укажи, что нужен review.
`.trim();
  } else if (ruleTopScore >= highThreshold) {
    shortlistPolicyText = `
Политика выбора:
- Rule-based слой дал сильный top candidate.
- В первую очередь проверь, подходит ли top candidate.
- Если top candidate не подходит, выбери лучшую категорию из shortlist.
- Если ни одна категория не подходит, верни category_id = null и укажи причину.
`.trim();
  } else {
    shortlistPolicyText = `
Политика выбора:
- Shortlist выглядит разумным, но не окончательным.
- Предпочитай выбор из shortlist.
- Если ни один кандидат не подходит, можешь выбрать категорию вне shortlist или вернуть category_id = null.
- Если выбор вне shortlist, кратко объясни почему shortlist оказался недостаточным.
`.trim();
  }

  const userPrompt = `
Товар (нормализованный текст):
${j.combined_text || ''}

Тип товара по эвристике: ${j.product_type_guess || 'unknown'}

Shortlist кандидатов категорий:
${shortlistText}

${ruleHint}

${shortlistPolicyText}

Задача:
- Выбери наиболее подходящую категорию для товара.
- Верни category_id, confidence и explanation.
- confidence должен быть числом от 0.0 до 1.0.
- explanation должен быть кратким, на русском, 1–3 предложения.
- Не добавляй комментарии вне JSON.
`.trim();

  return {
    json: {
      ...j,

      product_id: j.product_id !== undefined && j.product_id !== null && j.product_id !== ''
        ? Number(j.product_id)
        : null,

      product_raw_id: j.product_raw_id !== undefined && j.product_raw_id !== null && j.product_raw_id !== ''
        ? Number(j.product_raw_id)
        : null,

      run_id: j.run_id !== undefined && j.run_id !== null && j.run_id !== ''
        ? Number(j.run_id)
        : null,

      rule_top_category_id: ruleTopCategoryId,
      rule_top_score: ruleTopScore,
      shortlist_count: shortlist.length,
      shortlist_json: shortlist,

      deepseek_body: {
        model: 'deepseek-chat',
        messages: [
          {
            role: 'system',
            content: 'You classify pharmacy products into one category. Return ONLY a valid JSON object with keys: category_id, confidence, explanation.'
          },
          {
            role: 'user',
            content: userPrompt
          }
        ]
      },

      llm_prompt_debug: {
        system: 'You classify pharmacy products into one category. Return ONLY a valid JSON object with keys: category_id, confidence, explanation.',
        user: userPrompt
      }
    },
    pairedItem: index
  };
});

return items.map((item, index) => {
  const j = item.json || {};
  const shortlist = Array.isArray(j.shortlist_json) ? j.shortlist_json : [];
  const messages = Array.isArray(j.deepseek_body?.messages) ? j.deepseek_body.messages : [];

  return {
    json: {
      ...j,

      context: {
        run_id: j.run_id !== undefined && j.run_id !== null && j.run_id !== ''
          ? Number(j.run_id)
          : null,

        run_meta: j.run_meta || null,

        product_id: j.product_id !== undefined && j.product_id !== null && j.product_id !== ''
          ? Number(j.product_id)
          : null,

        product_raw_id: j.product_raw_id !== undefined && j.product_raw_id !== null && j.product_raw_id !== ''
          ? Number(j.product_raw_id)
          : null,

        rule_top_category_id: j.rule_top_category_id !== undefined && j.rule_top_category_id !== null && j.rule_top_category_id !== ''
          ? Number(j.rule_top_category_id)
          : null,

        rule_top_score: j.rule_top_score !== undefined && j.rule_top_score !== null && j.rule_top_score !== ''
          ? Number(j.rule_top_score)
          : null,

        shortlist_count: shortlist.length,
        shortlist_json: shortlist
      },

      prompt_system: messages[0]?.content || '',
      prompt_user: messages[1]?.content || ''
    },
    pairedItem: index
  };
});

function extractJsonString(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'object') return JSON.stringify(value);

  let text = String(value).trim();

  const codeFenceMatch = text.match(/^```(?:json)?\s*\n?([\s\S]+?)\n?```\s*$/i);
  if (codeFenceMatch) {
    text = codeFenceMatch[1].trim();
  }

  return text;
}

function safeParseJson(value) {
  const text = extractJsonString(value);

  if (!text) {
    return { ok: false, error: 'empty_output', parsed: null, raw_text: null };
  }

  try {
    return { ok: true, error: null, parsed: JSON.parse(text), raw_text: text };
  } catch (e) {
    return { ok: false, error: 'invalid_json', parsed: null, raw_text: text };
  }
}

function normalizeInt(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

function normalizeConfidence(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  if (n < 0 || n > 1) return null;
  return n;
}

function safeText(v) {
  if (v === undefined || v === null || v === '') return null;
  const s = String(v).trim();
  return s === '' ? null : s;
}

function safeNumber(v) {
  if (v === undefined || v === null || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function safeJson(v) {
  if (v === undefined || v === null) return null;
  return v;
}

return items.map((item, index) => {
  const root = item.json || {};
  const ctx = root.context || {};
  const C = root.constants || {};

  const STAGE = C.stage || {
    primary_llm: 'primary_llm'
  };

  const DECISION = C.decision_status || {
    classified: 'classified',
    pending_fallback: 'pending_fallback',
    needs_human_review: 'needs_human_review',
    error: 'error'
  };

  const FINAL = C.final_source || {
    llm: 'llm',
    system: 'system'
  };

  const NEXT = C.next_action || {
    none: 'none',
    fallback_2a: 'fallback_2a',
    judge: 'judge',
    human_review: 'human_review'
  };

  const ACTOR = C.actor_type || {
    llm: 'llm'
  };

  const LOG = C.log_status || {
    success: 'success',
    needs_review: 'needs_review',
    rejected: 'rejected',
    error: 'error'
  };

  const THRESHOLDS = C.thresholds || {
    min_confidence_ok: 0.60
  };

  const MODEL = C.model || {
    primary_actor_name: 'deepseek-chat'
  };

  const runId = normalizeInt(ctx.run_id ?? root.run_id);
  const productId = normalizeInt(ctx.product_id ?? root.product_id);
  const productRawId = normalizeInt(ctx.product_raw_id ?? root.product_raw_id);
  const ruleTopCategoryId = normalizeInt(ctx.rule_top_category_id ?? root.rule_top_category_id);
  const ruleTopScore = safeNumber(ctx.rule_top_score ?? root.rule_top_score);

  const shortlist = Array.isArray(ctx.shortlist_json)
    ? ctx.shortlist_json
    : (Array.isArray(root.shortlist_json) ? root.shortlist_json : []);

  const shortlistCount = safeNumber(ctx.shortlist_count ?? root.shortlist_count) ?? shortlist.length;

  const shortlistIds = new Set(
    shortlist
      .map(c => normalizeInt(c.category_id))
      .filter(v => v !== null)
      .map(String)
  );

  const rawModelOutput =
    root.output ??
    root.text ??
    root.response ??
    root.content ??
    root.result ??
    null;

  const parsedResult = safeParseJson(rawModelOutput);

  let llmCategoryId = null;
  let llmConfidence = null;
  let llmExplanation = null;

  let llmValidationPassed = false;
  let llmRejectReason = null;
  let llmNeedsReview = true;
  let categoryOutsideShortlist = false;

  if (!parsedResult.ok) {
    llmRejectReason = parsedResult.error;
  } else {
    const parsed = parsedResult.parsed || {};

    llmCategoryId = normalizeInt(parsed.category_id);
    llmConfidence = normalizeConfidence(parsed.confidence);
    llmExplanation = safeText(parsed.explanation);

    if (!llmExplanation) {
      llmRejectReason = 'missing_explanation';
    } else if (llmConfidence === null) {
      llmRejectReason = 'invalid_confidence';
    } else if (llmCategoryId === null) {
      llmRejectReason = 'null_category';
    } else {
      llmValidationPassed = true;
    }

    if (llmValidationPassed && shortlistCount > 0 && !shortlistIds.has(String(llmCategoryId))) {
      categoryOutsideShortlist = true;
      llmRejectReason = 'category_outside_shortlist';
    }
  }

  if (!llmValidationPassed) {
    llmNeedsReview = true;
  } else if (categoryOutsideShortlist) {
    llmNeedsReview = true;
  } else if (llmConfidence <= THRESHOLDS.min_confidence_ok) {
    llmNeedsReview = true;
  } else {
    llmNeedsReview = false;
  }

  let decisionStatus = DECISION.error;
  let finalSource = FINAL.system;
  let finalCategoryId = null;
  let finalConfidence = null;
  let finalExplanation = null;
  let nextAction = NEXT.human_review;

  if (llmValidationPassed && !categoryOutsideShortlist && !llmNeedsReview) {
    decisionStatus = DECISION.classified;
    finalSource = FINAL.llm;
    finalCategoryId = llmCategoryId;
    finalConfidence = llmConfidence;
    finalExplanation = llmExplanation;
    nextAction = NEXT.none;
  } else if (
    llmRejectReason === 'invalid_json' ||
    llmRejectReason === 'empty_output' ||
    llmRejectReason === 'null_category' ||
    llmRejectReason === 'category_outside_shortlist'
  ) {
    decisionStatus = DECISION.pending_fallback;
    finalSource = FINAL.system;
    nextAction = NEXT.fallback_2a;
  } else if (llmValidationPassed && llmNeedsReview) {
    decisionStatus = DECISION.needs_human_review;
    finalSource = FINAL.system;
    nextAction = NEXT.human_review;
  } else {
    decisionStatus = DECISION.needs_human_review;
    finalSource = FINAL.system;
    nextAction = NEXT.human_review;
  }

  const llmRawJson = safeJson(parsedResult.ok ? parsedResult.parsed : null);
  const llmRawOutputText = safeText(parsedResult.raw_text);

  const normalizedLlmExplanation = safeText(llmExplanation);
  const normalizedFinalExplanation = safeText(finalExplanation);
  const normalizedFinalSource = safeText(finalSource);
  const normalizedDecisionStatus = safeText(decisionStatus);
  const normalizedRejectReason = safeText(llmRejectReason);
  const normalizedNextAction = safeText(nextAction);

  const routingHint = {
    trigger_reason: normalizedRejectReason,
    shortlist_count: shortlistCount,
    category_outside_shortlist: categoryOutsideShortlist,
    llm_validation_passed: llmValidationPassed,
    llm_confidence: llmConfidence,
    suggested_next_action: normalizedNextAction
  };

  const productClassificationUpdate = {
    product_id: productId,
    product_raw_id: productRawId,
    latest_run_id: runId,
    llm_category_id: llmCategoryId,
    llm_confidence: llmConfidence,
    llm_explanation: normalizedLlmExplanation,
    llm_needs_review: llmNeedsReview,
    llm_validation_passed: llmValidationPassed,
    llm_reject_reason: normalizedRejectReason,
    llm_raw_json: llmRawJson,
    next_action: normalizedNextAction,
    routing_hint: routingHint,
    final_category_id: finalCategoryId,
    final_confidence: finalConfidence,
    final_explanation: normalizedFinalExplanation,
    final_source: normalizedFinalSource,
    decision_status: normalizedDecisionStatus
  };

  const productClassificationLogInsert = {
    run_id: runId,
    product_id: productId,
    product_raw_id: productRawId,
    stage: STAGE.primary_llm,
    actor_type: ACTOR.llm,
    actor_name: MODEL.primary_actor_name,
    status: llmValidationPassed
      ? (llmNeedsReview ? LOG.needs_review : LOG.success)
      : LOG.rejected,
    selected_category_id: llmCategoryId,
    confidence: llmConfidence,
    explanation: normalizedLlmExplanation,
    validation_passed: llmValidationPassed,
    error_message: normalizedRejectReason,
    decision_status: normalizedDecisionStatus,
    next_action: normalizedNextAction,
    input_payload: {
      shortlist_count: shortlistCount,
      shortlist_json: shortlist,
      rule_top_category_id: ruleTopCategoryId,
      rule_top_score: ruleTopScore
    },
    output_payload: safeJson(
      parsedResult.ok
        ? parsedResult.parsed
        : { raw_output: llmRawOutputText }
    ),
    routing_hint: routingHint
  };

  return {
    json: {
      ...root,

      run_id: runId,
      product_id: productId,
      product_raw_id: productRawId,
      rule_top_category_id: ruleTopCategoryId,
      rule_top_score: ruleTopScore,
      shortlist_count: shortlistCount,
      shortlist_json: shortlist,

      llm_category_id: llmCategoryId,
      llm_confidence: llmConfidence,
      llm_explanation: normalizedLlmExplanation,
      llm_needs_review: llmNeedsReview,
      llm_validation_passed: llmValidationPassed,
      llm_reject_reason: normalizedRejectReason,

      next_action: normalizedNextAction,
      routing_hint: routingHint,

      decision_status: normalizedDecisionStatus,
      final_source: normalizedFinalSource,
      final_category_id: finalCategoryId,
      final_confidence: finalConfidence,
      final_explanation: normalizedFinalExplanation,

      llm_raw_output_text: llmRawOutputText,
      llm_raw_json: llmRawJson,

      product_classification_update: productClassificationUpdate,
      product_classification_log_insert: productClassificationLogInsert
    },
    pairedItem: index
  };
});

function sqlText(value) {
  if (value === undefined || value === null) return null;
  const s = String(value).trim();
  return s === '' ? null : s;
}

function sqlNumber(value) {
  if (value === undefined || value === null || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function sqlBoolean(value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const v = value.trim().toLowerCase();
    if (['true', '1', 'yes', 'y'].includes(v)) return true;
    if (['false', '0', 'no', 'n'].includes(v)) return false;
  }
  return null;
}

function sqlJson(value) {
  if (value === undefined || value === null || value === '') return null;
  return value;
}

return items.map((item, index) => {
  const j = item.json || {};

  const productClassificationUpdate = {
    product_id: sqlNumber(j.product_id),
    product_raw_id: sqlNumber(j.product_raw_id),
    latest_run_id: sqlNumber(j.run_id),

    workflow_version: sqlText(j.workflow_version),
    prompt_version: sqlText(j.prompt_version),

    rule_top_category_id: sqlNumber(j.rule_top_category_id),
    rule_top_score: sqlNumber(j.rule_top_score),
    rule_shortlist_id: sqlNumber(j.rule_shortlist_id),
    rule_decision_status: sqlText(j.rule_decision_status),

    llm_category_id: sqlNumber(j.llm_category_id),
    llm_confidence: sqlNumber(j.llm_confidence),
    llm_explanation: sqlText(j.llm_explanation),
    llm_needs_review: sqlBoolean(j.llm_needs_review),
    llm_validation_passed: sqlBoolean(j.llm_validation_passed),
    llm_reject_reason: sqlText(j.llm_reject_reason),
    llm_raw_json: sqlJson(j.llm_raw_json),

    judge_category_id: sqlNumber(j.judge_category_id),
    judge_confidence: sqlNumber(j.judge_confidence),
    judge_explanation: sqlText(j.judge_explanation),
    judge_needs_review: sqlBoolean(j.judge_needs_review),
    judge_raw_json: sqlJson(j.judge_raw_json),

    fallback_2a_direction: sqlText(j.fallback_2a_direction),
    fallback_2a_block_family: sqlText(j.fallback_2a_block_family),
    fallback_2a_family_code: sqlText(j.fallback_2a_family_code),
    fallback_2a_nosology_hint: sqlText(j.fallback_2a_nosology_hint),
    fallback_2a_confidence: sqlNumber(j.fallback_2a_confidence),
    fallback_2a_explanation: sqlText(j.fallback_2a_explanation),
    fallback_2a_raw_json: sqlJson(j.fallback_2a_raw_json),

    fallback_2b_category_id: sqlNumber(j.fallback_2b_category_id),
    fallback_2b_confidence: sqlNumber(j.fallback_2b_confidence),
    fallback_2b_explanation: sqlText(j.fallback_2b_explanation),
    fallback_2b_raw_json: sqlJson(j.fallback_2b_raw_json),

    final_category_id: sqlNumber(j.final_category_id),
    final_confidence: sqlNumber(j.final_confidence),
    final_explanation: sqlText(j.final_explanation),
    final_source: sqlText(j.final_source),

    decision_status: sqlText(j.decision_status),
    next_action: sqlText(j.next_action),
    routing_hint: sqlJson(j.routing_hint)
  };

  return {
    json: {
      ...j,
      product_classification_update: productClassificationUpdate
    },
    pairedItem: {
      item: index
    }
  };
});

function sqlText(value) {
  if (value === undefined || value === null) return null;
  const s = String(value).trim();
  return s === '' ? null : s;
}

function sqlNumber(value) {
  if (value === undefined || value === null || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function sqlBoolean(value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const v = value.trim().toLowerCase();
    if (['true', '1', 'yes', 'y'].includes(v)) return true;
    if (['false', '0', 'no', 'n'].includes(v)) return false;
  }
  return null;
}

function sqlJson(value) {
  if (value === undefined || value === null || value === '') return null;
  return value;
}

return items.map((item, index) => {
  const j = item.json || {};

  const stage = sqlText(j.stage) || 'primary_llm';
  const actorType = sqlText(j.actor_type) || 'llm';
  const actorName = sqlText(j.actor_name) || 'deepseek-chat';

  const selectedCategoryId =
    sqlNumber(j.final_category_id) ??
    sqlNumber(j.fallback_2b_category_id) ??
    sqlNumber(j.judge_category_id) ??
    sqlNumber(j.llm_category_id);

  const confidence =
    sqlNumber(j.final_confidence) ??
    sqlNumber(j.fallback_2b_confidence) ??
    sqlNumber(j.judge_confidence) ??
    sqlNumber(j.llm_confidence) ??
    sqlNumber(j.fallback_2a_confidence);

  const explanation =
    sqlText(j.final_explanation) ??
    sqlText(j.fallback_2b_explanation) ??
    sqlText(j.judge_explanation) ??
    sqlText(j.llm_explanation) ??
    sqlText(j.fallback_2a_explanation);

  const validationPassed =
    sqlBoolean(j.validation_passed) ??
    sqlBoolean(j.fallback_2b_validation_passed) ??
    sqlBoolean(j.llm_validation_passed);

  const errorMessage =
    sqlText(j.error_message) ??
    sqlText(j.fallback_2b_reject_reason) ??
    sqlText(j.llm_reject_reason);

  const inputPayload = {
    product_id: sqlNumber(j.product_id),
    product_raw_id: sqlNumber(j.product_raw_id),
    run_id: sqlNumber(j.run_id),
    stage,
    workflow_version: sqlText(j.workflow_version),
    prompt_version: sqlText(j.prompt_version),
    combined_text: sqlText(j.combined_text),
    product_type_guess: sqlText(j.product_type_guess),
    rule_top_category_id: sqlNumber(j.rule_top_category_id),
    rule_top_score: sqlNumber(j.rule_top_score),
    rule_shortlist_id: sqlNumber(j.rule_shortlist_id),
    shortlist_json: sqlJson(j.shortlist_json),
    shortlist_count: sqlNumber(j.shortlist_count),
    next_action: sqlText(j.next_action),
    routing_hint: sqlJson(j.routing_hint)
  };

  const outputPayload = {
    llm_category_id: sqlNumber(j.llm_category_id),
    llm_confidence: sqlNumber(j.llm_confidence),
    llm_explanation: sqlText(j.llm_explanation),
    llm_needs_review: sqlBoolean(j.llm_needs_review),
    llm_validation_passed: sqlBoolean(j.llm_validation_passed),
    llm_reject_reason: sqlText(j.llm_reject_reason),
    llm_raw_json: sqlJson(j.llm_raw_json),

    fallback_2a_direction: sqlText(j.fallback_2a_direction),
    fallback_2a_block_family: sqlText(j.fallback_2a_block_family),
    fallback_2a_family_code: sqlText(j.fallback_2a_family_code),
    fallback_2a_nosology_hint: sqlText(j.fallback_2a_nosology_hint),
    fallback_2a_confidence: sqlNumber(j.fallback_2a_confidence),
    fallback_2a_explanation: sqlText(j.fallback_2a_explanation),
    fallback_2a_raw_json: sqlJson(j.fallback_2a_raw_json),

    fallback_2b_category_id: sqlNumber(j.fallback_2b_category_id),
    fallback_2b_confidence: sqlNumber(j.fallback_2b_confidence),
    fallback_2b_explanation: sqlText(j.fallback_2b_explanation),
    fallback_2b_raw_json: sqlJson(j.fallback_2b_raw_json),

    judge_category_id: sqlNumber(j.judge_category_id),
    judge_confidence: sqlNumber(j.judge_confidence),
    judge_explanation: sqlText(j.judge_explanation),
    judge_needs_review: sqlBoolean(j.judge_needs_review),
    judge_raw_json: sqlJson(j.judge_raw_json),

    final_category_id: sqlNumber(j.final_category_id),
    final_confidence: sqlNumber(j.final_confidence),
