function norm(s) {
  if (s === null || s === undefined) return '';
  return String(s)
    .toLowerCase()
    .replace(/ё/g, 'е')
    .replace(/[^\p{L}\p{N}\s/+.-]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenize(text) {
  return norm(text)
    .split(/\s+/)
    .map(t => t.trim())
    .filter(Boolean);
}

function splitTerms(text) {
  if (!text) return [];
  const stop = new Set([
    'мг', 'мл', 'г', 'кг', 'ml', 'mg', 'n', 'na', 'cl', 'ca', 'k', 'd',
    'и', 'или', 'для', 'при', 'под', 'над', 'без', 'от', 'до', 'по',
    'средство', 'средства', 'форма', 'формы', 'дети', 'взрослые'
  ]);
  return Array.from(new Set(
    norm(text)
      .split(/[/,;|()+]+/)
      .flatMap(part => part.split(/\s+/))
      .map(s => s.trim())
      .filter(Boolean)
      .filter(t => t.length >= 3)
      .filter(t => !/^\d+$/.test(t))
      .filter(t => !stop.has(t))
  ));
}

function hasAnyWord(text, words) {
  if (!words || !words.length) return false;
  const tokens = new Set(tokenize(text).filter(w => w.length >= 3));
  const list = Array.isArray(words) ? words : [];
  return list.some(w => tokens.has(norm(w)));
}

function routeHints(text) {
  const t = norm(text);
  return {
    oral: /(сироп|таблет|капсул|капс\.|пастил|леденц|порошок|суспенз|внутрь|оральн)/.test(t),
    nasal: /(назал|в нос|капли в нос|спрей в нос)/.test(t),
    throat: /(горло|спрей для горла|пастил|леденц)/.test(t),
    eye: /(глаз|глазн)/.test(t),
    skin: /(крем|маз|гель|лосьон|сыворотк|маска|пенка|шампунь|флюид|бальзам)/.test(t),
    external: /(наруж|местн|крем|маз|гель|лосьон|сыворотк|маска|пенка|шампунь|флюид|бальзам)/.test(t),
    infusion: /(инфуз|р-р д\/инфуз|раствор д\/инфуз|в\/в)/.test(t),
    injection: /(ампул|инъекц|шприц)/.test(t),
  };
}

function ageHints(text) {
  const t = norm(text);
  return {
    child: /(дет|baby|kid|junior|малыш|младен|0\+|1\+|2\+|3\+)/.test(t),
    adult: /(взросл)/.test(t),
  };
}

function guessProductType(text) {
  const t = norm(text);
  if (/(подгузник|трусики-подгузники|трусики подгузники|трусики|памперс)/.test(t)) return 'infant_hygiene';
  if (/(прокладк|тампон|ежедневк)/.test(t)) return 'female_hygiene';
  if (/(шампунь|пенка|гель д\/умывания|умыван|лосьон|маска д\/лица|сыворотк|крем д\/рук|крем д\/лица|крем для рук|крем для лица|увлажняющ|солнцезащитн|флюид|косметическ)/.test(t)) return 'cosmetic';
  if (/(шприц|игл|катетер|тест[- ]?полоск|тест система|межпальцевый разделитель|ортопед|бинт|пластыр|ингалятор|термометр)/.test(t)) return 'device';
  if (/(витамин|бета-каротин|бета каротин|спирулин|бад|now foods|нау фудс)/.test(t)) return 'supplement';
  if (/(р-р д\/инфуз|инфузи|натрия хлорид|ампул|инъекц)/.test(t)) return 'infusion_drug';
  if (/(таб\.|таблет|капсул|сироп|суспенз|порошок|драже)/.test(t)) return 'drug';
  if (/(закваск|сметан|йогурт|кефир)/.test(t)) return 'food';
  return 'other';
}

function looksLikeCosmeticCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const dir = norm(c.direction);
  return code.startsWith('COSM_') || /космет|уход|лица|рук|тела|волос|шампун|сыворот|маска|пенка|гигиен/.test(name) || /космет|уход|гигиен/.test(dir);
}

function looksLikeInfantHygieneCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  return code.startsWith('FAM_CAT_INFANT') || /подгузник|трусики/.test(name);
}

function looksLikeFemaleHygieneCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  return code.startsWith('COSM_CAT_HYGIENE') || /прокладк|тампон|ежедневк/.test(name) || /гигиенические женские/.test(name);
}

function looksLikeDeviceCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const dir = norm(c.direction);
  return code.startsWith('LS_MD_') || /шприц|игл|тест|ортопед|стельк|разделител|бинт|пластыр|инструмент/.test(name) || /медицинск/.test(dir);
}

function looksLikeSupplementCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const dir = norm(c.direction);
  return code.startsWith('BA_') || /витамин|минерал|комплекс|иммун|бад|спирулин|каротин/.test(name) || /бад/.test(dir);
}

function looksLikeInfusionDrugCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const mnn = norm(c.mnn_cluster);
  return code.startsWith('LS_INF_') || /инфуз|раствор|регидрон|рингер|натрия|хлорид/.test(name) || /натрия|хлорид|инфуз/.test(mnn);
}

function looksLikeDrugCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  return code.startsWith('LS_') && !code.startsWith('LS_MD_') && !code.startsWith('LS_INF_');
}

function familyCodePrefix(code) {
  const parts = String(code || '').split('_').filter(Boolean);
  if (parts.length >= 2) return parts.slice(0, 2).join('_');
  return parts[0] || '';
}

function blockFamilyFromCategory(c) {
  const level = Number(c.hierarchy_level) || 0;
  if (level <= 2) return c.category_name || familyCodePrefix(c.category_code);
  return familyCodePrefix(c.category_code);
}



return products.map((j, index) => {
const baseText = norm([
  j.combined_text,
  j.product_type_guess
].filter(Boolean).join(' '));

const productTypeGuess = j.product_type_guess || guessProductType(baseText);
const rh = routeHints(baseText);
const ah = ageHints(baseText);

const branchScores = new Map();

for (const c of categories) {
  const catCode = (c.category_code || '').toUpperCase();

  if (productTypeGuess === 'cosmetic' && !looksLikeCosmeticCategory(c)) continue;
  if (productTypeGuess === 'infant_hygiene' && !looksLikeInfantHygieneCategory(c)) continue;
  if (productTypeGuess === 'female_hygiene' && !looksLikeFemaleHygieneCategory(c)) continue;
  if (productTypeGuess === 'device' && !looksLikeDeviceCategory(c)) continue;
  if (productTypeGuess === 'supplement' && !looksLikeSupplementCategory(c)) continue;
  if (productTypeGuess === 'infusion_drug' && !looksLikeInfusionDrugCategory(c)) continue;
  if (productTypeGuess === 'drug' && !looksLikeDrugCategory(c)) continue;
  if (productTypeGuess === 'food') continue;

  let score = 0;
  const reasons = [];

  const categoryTerms = splitTerms(c.category_name);
  const nosologyTerms = splitTerms(c.need_nosology);
  const mnnTerms = splitTerms(c.mnn_cluster);
  const commentTerms = splitTerms(c.inclusion_comment).filter(t => t.length >= 5);

  const ageSegment = norm(c.age_segment);
  const route = norm(c.administration_route);

  for (const term of categoryTerms) {
    if (term && baseText.includes(term)) { score += 7; reasons.push(`category:${term}`); }
  }
  for (const term of nosologyTerms) {
    if (term && baseText.includes(term)) { score += 5; reasons.push(`nosology:${term}`); }
  }
  for (const term of mnnTerms) {
    if (term && baseText.includes(term)) { score += 6; reasons.push(`mnn:${term}`); }
  }
  for (const term of commentTerms.slice(0, 8)) {
    if (term && baseText.includes(term)) { score += 2; reasons.push(`comment:${term}`); }
  }

  if (hasAnyWord(baseText, c.include_keywords || [])) { score += 10; reasons.push('include_keywords'); }
  if (hasAnyWord(baseText, c.exclude_keywords || [])) { score -= 12; reasons.push('exclude_keywords'); }

  if (ageSegment.includes('дет') && ah.child) { score += 4; reasons.push('age:child'); }
  if (ageSegment.includes('взрос') && ah.adult) { score += 4; reasons.push('age:adult'); }

  if (route.includes('назал') && rh.nasal) { score += 5; reasons.push('route:nasal'); }
  if (route.includes('внутрь') && rh.oral) { score += 4; reasons.push('route:oral'); }
  if (route.includes('орофар') && rh.throat) { score += 5; reasons.push('route:throat'); }
  if (route.includes('наруж') && rh.external) { score += 3; reasons.push('route:external'); }
  if (route.includes('глаз') && rh.eye) { score += 5; reasons.push('route:eye'); }

  if (productTypeGuess === 'infusion_drug' && rh.infusion && catCode.startsWith('LS_INF_')) { score += 8; reasons.push('product_type:infusion_drug'); }
  if (productTypeGuess === 'device' && catCode.startsWith('LS_MD_')) { score += 5; reasons.push('product_type:device'); }
  if (productTypeGuess === 'supplement' && catCode.startsWith('BA_')) { score += 6; reasons.push('product_type:supplement'); }
  if (productTypeGuess === 'cosmetic' && catCode.startsWith('COSM_')) { score += 6; reasons.push('product_type:cosmetic'); }

  const hasStrongMatch =
    reasons.some(r => r.startsWith('category:')) ||
    reasons.some(r => r.startsWith('nosology:')) ||
    reasons.some(r => r.startsWith('mnn:')) ||
    reasons.some(r => r.startsWith('comment:')) ||
    reasons.includes('include_keywords') ||
    reasons.includes('product_type:infusion_drug') ||
    reasons.includes('product_type:device') ||
    reasons.includes('product_type:supplement') ||
    reasons.includes('product_type:cosmetic');

  if (!hasStrongMatch) score = 0;
  if (score <= 0) continue;

  const direction = c.direction || null;
  const blockFamily = blockFamilyFromCategory(c);
  const familyCode = familyCodePrefix(c.category_code);
  const branchKey = `${direction || ''}|${blockFamily || ''}|${familyCode || ''}`;

  const existing = branchScores.get(branchKey) || {
    direction,
    block_family: blockFamily,
    family_code: familyCode,
    score: 0,
    reasons: [],
    sample_category_id: c.id,
    sample_category_name: c.category_name,
    hierarchy_level: c.hierarchy_level,
    need_nosology: c.need_nosology || null
  };

  existing.score += score;
  existing.reasons.push(...reasons);
  branchScores.set(branchKey, existing);
}

const branchCandidates = Array.from(branchScores.values())
  .sort((a, b) => b.score - a.score)
  .slice(0, 8)
  .map((b, idx) => ({
    rank: idx + 1,
    direction: b.direction,
    block_family: b.block_family,
    family_code: b.family_code,
    score: b.score,
    reasons: Array.from(new Set(b.reasons)).slice(0, 12),
    sample_category_id: b.sample_category_id,
    sample_category_name: b.sample_category_name,
    hierarchy_level: b.hierarchy_level,
    need_nosology: b.need_nosology
  }));


  const skipLlm = branchCandidates.length === 0;

  return {
    json: {
      ...j,
      branch_candidates_json: branchCandidates,
      branch_candidates_count: branchCandidates.length,
      skip_llm: skipLlm,
      product_type_guess: productTypeGuess
    },
    pairedItem: { item: index }
  };
});

