    const rawModelOutput = root.output ?? root.text ?? root.response ?? root.content ?? root.result ?? null;
    const parsedResult = safeParseJson(rawModelOutput);
    fallback2aRawOutputText = safeText(parsedResult.raw_text);
    fallback2aRawJson = safeJson(parsedResult.ok ? parsedResult.parsed : null);

    if (!parsedResult.ok) {
      fallback2aRejectReason = parsedResult.error;
    } else {
      const parsed = parsedResult.parsed || {};
      fallback2aDirection = safeText(parsed.direction);
      fallback2aBlockFamily = safeText(parsed.block_family);
      fallback2aFamilyCode = safeText(parsed.family_code);
      fallback2aNosologyHint = safeText(parsed.nosology_hint);
      fallback2aConfidence = normalizeConfidence(parsed.confidence);
      fallback2aExplanation = safeText(parsed.explanation);

      if (!fallback2aExplanation) {
        fallback2aRejectReason = 'missing_explanation';
      } else if (fallback2aConfidence === null) {
        fallback2aRejectReason = 'invalid_confidence';
      } else if (!fallback2aDirection || !fallback2aBlockFamily || !fallback2aFamilyCode) {
        fallback2aRejectReason = 'missing_branch_fields';
      } else {
        const matched = branchCandidates.some(c =>
          safeText(c.direction) === fallback2aDirection &&
          safeText(c.block_family) === fallback2aBlockFamily &&
          safeText(c.family_code) === fallback2aFamilyCode
        );
        if (!matched) {
          fallback2aRejectReason = 'branch_not_in_candidates';
        } else {
          fallback2aValidationPassed = true;
        }
      }
    }
  }

  let decisionStatus = DECISION.needs_human_review;
  let nextAction = NEXT.human_review;
  let logStatus = LOG.needs_review;

  if (fallback2aValidationPassed && fallback2aConfidence > THRESHOLDS.min_confidence_2a_ok) {
    decisionStatus = DECISION.pending_fallback;
    nextAction = NEXT.fallback_2b;
    logStatus = LOG.success;
  } else if (fallback2aValidationPassed) {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = LOG.needs_review;
  } else {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = fallback2aRejectReason ? LOG.rejected : LOG.needs_review;
  }

  const routingHint = {
    stage: STAGE.fallback_2a,
