  const ACTOR = C.actor_type || { llm: 'llm' };
  const LOG = C.log_status || { success: 'success', needs_review: 'needs_review', rejected: 'rejected' };
  const THRESHOLDS = C.thresholds || { min_confidence_2b_ok: 0.60 };
