  const shortlist = Array.isArray(ctx.branch_shortlist_json)
    ? ctx.branch_shortlist_json
    : (Array.isArray(root.branch_shortlist_json) ? root.branch_shortlist_json : []);

  const shortlistIds = new Set(
    shortlist.map(c => normalizeInt(c.category_id)).filter(v => v !== null).map(String)
  );

  const skipLlm = root.skip_llm === true || ctx.skip_llm === true || shortlist.length === 0;

  let fallback2bCategoryId = null;
  let fallback2bConfidence = null;
  let fallback2bExplanation = null;
  let fallback2bValidationPassed = false;
  let fallback2bRejectReason = null;
  let fallback2bRawJson = null;
  let fallback2bRawOutputText = null;
  let categoryOutsideShortlist = false;

  if (skipLlm) {
    fallback2bRejectReason = 'empty_branch_shortlist';
  } else {
    const rawModelOutput = root.output ?? root.text ?? root.response ?? root.content ?? root.result ?? null;
    const parsedResult = safeParseJson(rawModelOutput);
    fallback2bRawOutputText = safeText(parsedResult.raw_text);
    fallback2bRawJson = safeJson(parsedResult.ok ? parsedResult.parsed : null);

    if (!parsedResult.ok) {
      fallback2bRejectReason = parsedResult.error;
    } else {
      const parsed = parsedResult.parsed || {};
      fallback2bCategoryId = normalizeInt(parsed.category_id);
      fallback2bConfidence = normalizeConfidence(parsed.confidence);
      fallback2bExplanation = safeText(parsed.explanation);

      if (!fallback2bExplanation) {
        fallback2bRejectReason = 'missing_explanation';
      } else if (fallback2bConfidence === null) {
        fallback2bRejectReason = 'invalid_confidence';
      } else if (fallback2bCategoryId === null) {
        fallback2bRejectReason = 'null_category';
      } else if (!shortlistIds.has(String(fallback2bCategoryId))) {
        categoryOutsideShortlist = true;
        fallback2bRejectReason = 'category_outside_shortlist';
      } else {
        fallback2bValidationPassed = true;
      }
    }
  }

  const primaryConflict = llmCategoryId !== null && fallback2bCategoryId !== null && llmCategoryId !== fallback2bCategoryId;

  let decisionStatus = DECISION.needs_human_review;
  let finalSource = FINAL.system;
  let finalCategoryId = null;
  let finalConfidence = null;
  let finalExplanation = null;
  let nextAction = NEXT.human_review;
  let logStatus = LOG.needs_review;

  if (skipLlm || fallback2bRejectReason === 'empty_branch_shortlist') {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = LOG.rejected;
  } else if (!fallback2bValidationPassed) {
    decisionStatus = DECISION.needs_human_review;
    nextAction = (fallback2bRejectReason === 'null_category' || categoryOutsideShortlist)
      ? NEXT.judge
      : NEXT.human_review;
    logStatus = LOG.rejected;
  } else if (primaryConflict) {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.judge;
    logStatus = LOG.needs_review;
  } else if (fallback2bConfidence > THRESHOLDS.min_confidence_2b_ok) {
    decisionStatus = DECISION.classified;
    finalSource = FINAL.fallback_2b;
    finalCategoryId = fallback2bCategoryId;
    finalConfidence = fallback2bConfidence;
    finalExplanation = fallback2bExplanation;
    nextAction = NEXT.none;
    logStatus = LOG.success;
  } else {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.judge;
    logStatus = LOG.needs_review;
  }

  const routingHint = {
    stage: STAGE.fallback_2b,
    branch_shortlist_count: shortlist.length,
    fallback_2b_validation_passed: fallback2bValidationPassed,
    fallback_2b_confidence: fallback2bConfidence,
    fallback_2b_reject_reason: fallback2bRejectReason,
    category_outside_shortlist: categoryOutsideShortlist,
    primary_conflict: primaryConflict,
    suggested_next_action: nextAction,
  };

  const productClassificationUpdate = {
    product_id: productId,
    product_raw_id: productRawId,
    latest_run_id: runId,
    workflow_version: WORKFLOW_VERSION,
    prompt_version: PROMPT_VERSION,
    rule_top_category_id: safeNumber(root.rule_top_category_id),
    rule_top_score: safeNumber(root.rule_top_score),
    rule_shortlist_id: safeNumber(root.rule_shortlist_id),
    rule_decision_status: safeText(root.rule_decision_status),
    llm_category_id: safeNumber(root.llm_category_id),
    llm_confidence: safeNumber(root.llm_confidence),
    llm_explanation: safeText(root.llm_explanation),
    llm_needs_review: root.llm_needs_review ?? null,
    llm_validation_passed: root.llm_validation_passed ?? null,
    llm_reject_reason: safeText(root.llm_reject_reason),
    llm_raw_json: safeJson(root.llm_raw_json),
    fallback_2a_direction: safeText(root.fallback_2a_direction),
    fallback_2a_block_family: safeText(root.fallback_2a_block_family),
    fallback_2a_family_code: safeText(root.fallback_2a_family_code),
    fallback_2a_nosology_hint: safeText(root.fallback_2a_nosology_hint),
    fallback_2a_confidence: safeNumber(root.fallback_2a_confidence),
    fallback_2a_explanation: safeText(root.fallback_2a_explanation),
    fallback_2a_raw_json: safeJson(root.fallback_2a_raw_json),
    fallback_2b_category_id: fallback2bCategoryId,
    fallback_2b_confidence: fallback2bConfidence,
    fallback_2b_explanation: fallback2bExplanation,
    fallback_2b_raw_json: fallback2bRawJson,
    final_category_id: finalCategoryId,
    final_confidence: finalConfidence,
    final_explanation: finalExplanation,
    final_source: finalSource,
    decision_status: decisionStatus,
    next_action: nextAction,
    routing_hint: routingHint,
  };

  return {
    json: {
      ...root,
      run_id: runId,
      product_id: productId,
      product_raw_id: productRawId,
      stage: STAGE.fallback_2b,
      actor_type: ACTOR.llm,
      actor_name: MODEL.fallback_actor_name,
      workflow_version: WORKFLOW_VERSION,
      prompt_version: PROMPT_VERSION,
      fallback_2b_category_id: fallback2bCategoryId,
      fallback_2b_confidence: fallback2bConfidence,
      fallback_2b_explanation: fallback2bExplanation,
      fallback_2b_validation_passed: fallback2bValidationPassed,
      fallback_2b_reject_reason: fallback2bRejectReason,
      fallback_2b_raw_json: fallback2bRawJson,
      fallback_2b_raw_output_text: fallback2bRawOutputText,
      branch_shortlist_json: shortlist,
      branch_shortlist_count: shortlist.length,
      validation_passed: fallback2bValidationPassed,
      error_message: fallback2bRejectReason,
      decision_status: decisionStatus,
      next_action: nextAction,
      final_source: finalSource,
      final_category_id: finalCategoryId,
      final_confidence: finalConfidence,
      final_explanation: finalExplanation,
      routing_hint: routingHint,
      product_classification_update: productClassificationUpdate,
    },
    pairedItem: index,
  };
});

function withoutStaleLlmOutput(j) {
  const src = j || {};
  const {
    output,
    text,
    response,
    content,
    result,
    llm_raw_output_text,
    ...rest
  } = src;
  return rest;
}

return items.map((item, index) => {
  const j = withoutStaleLlmOutput(item.json);
  const C = j.constants || {};
  const WORKFLOW_VERSION = 'stage2_judge_v1';
  const PROMPT_VERSION = 'prompt_judge_v1';

  const ruleShortlist = Array.isArray(j.shortlist_json) ? j.shortlist_json : [];
  const branchShortlist = Array.isArray(j.branch_shortlist_json) ? j.branch_shortlist_json : [];

  const formatShortlist = (list, label) => {
    if (!list.length) return `${label}: EMPTY`;
    return list.map((c, idx) => {
      const reasons = Array.isArray(c.reasons) ? c.reasons.join(', ') : '';
      return `${idx + 1}. id=${c.category_id}, code=${c.category_code || ''}, name=${c.category_name || ''}, score=${c.score ?? ''}, reasons=${reasons}`;
    }).join('\n');
  };

  const primaryRound = {
    llm_category_id: j.llm_category_id ?? null,
    llm_confidence: j.llm_confidence ?? null,
    llm_explanation: j.llm_explanation ?? null,
    llm_validation_passed: j.llm_validation_passed ?? null,
    llm_reject_reason: j.llm_reject_reason ?? null,
    rule_top_category_id: j.rule_top_category_id ?? null,
    rule_top_score: j.rule_top_score ?? null,
  };

  const fallback2a = {
    direction: j.fallback_2a_direction ?? null,
    block_family: j.fallback_2a_block_family ?? null,
    family_code: j.fallback_2a_family_code ?? null,
    nosology_hint: j.fallback_2a_nosology_hint ?? null,
    confidence: j.fallback_2a_confidence ?? null,
    explanation: j.fallback_2a_explanation ?? null,
  };

  const fallback2b = {
    category_id: j.fallback_2b_category_id ?? null,
    confidence: j.fallback_2b_confidence ?? null,
    explanation: j.fallback_2b_explanation ?? null,
    validation_passed: j.fallback_2b_validation_passed ?? null,
    reject_reason: j.fallback_2b_reject_reason ?? null,
  };

  const disputeContext = {
    routing_hint: j.routing_hint ?? null,
    primary_conflict: j.routing_hint?.primary_conflict ?? null,
    fallback_2b_reject_reason: j.fallback_2b_reject_reason ?? null,
    suggested_next_action: j.next_action ?? null,
  };

  const promptSystem =
    'You are a senior pharmacy product classification judge. Review prior automated rounds and return ONLY valid JSON with keys: winner_source, category_id, confidence, explanation, needs_human_review. winner_source must be one of: llm, fallback_2b, none. category_id must be from the allowed candidate ids or null if none fits.';

  const promptUser = `
Товар:
${j.combined_text || ''}

Тип товара: ${j.product_type_guess || 'unknown'}
run_id: ${j.run_id ?? ''}

Primary LLM (P1):
${JSON.stringify(primaryRound, null, 2)}

Fallback 2A (ветка):
${JSON.stringify(fallback2a, null, 2)}

Fallback 2B (категория в ветке):
${JSON.stringify(fallback2b, null, 2)}

Контекст спора:
${JSON.stringify(disputeContext, null, 2)}

Rule shortlist (primary):
${formatShortlist(ruleShortlist, 'rule')}

Branch shortlist (fallback 2B):
${formatShortlist(branchShortlist, 'branch')}

Задача:
- Выбери финальную category_id из объединения shortlist-ов выше, либо null если ни одна не подходит.
- winner_source: чей ответ вы предпочитаете (llm | fallback_2b | none).
- confidence: 0.0–1.0; explanation: 1–3 предложения на русском.
- needs_human_review=true если уверенность низкая или кандидаты противоречивы.
- Верни только JSON без markdown.
`.trim();

  return {
    json: {
      ...j,
      workflow_version: WORKFLOW_VERSION,
      prompt_version: PROMPT_VERSION,
      context: {
        run_id: j.run_id !== undefined && j.run_id !== null && j.run_id !== '' ? Number(j.run_id) : null,
        product_id: j.product_id !== undefined && j.product_id !== null && j.product_id !== '' ? Number(j.product_id) : null,
        product_raw_id: j.product_raw_id !== undefined && j.product_raw_id !== null && j.product_raw_id !== '' ? Number(j.product_raw_id) : null,
        primary_round: primaryRound,
        fallback_2a: fallback2a,
        fallback_2b: fallback2b,
        dispute_context: disputeContext,
        rule_shortlist_json: ruleShortlist,
        branch_shortlist_json: branchShortlist,
      },
      prompt_system: promptSystem,
      prompt_user: promptUser,
    },
    pairedItem: index,
  };
});

function extractJsonString(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'object') return JSON.stringify(value);
  let text = String(value).trim();
  const codeFenceMatch = text.match(/^```(?:json)?\s*\n?([\s\S]+?)\n?```\s*$/i);
  if (codeFenceMatch) text = codeFenceMatch[1].trim();
  return text;
}

function safeParseJson(value) {
  const text = extractJsonString(value);
  if (!text) return { ok: false, error: 'empty_output', parsed: null, raw_text: null };
  try {
    return { ok: true, error: null, parsed: JSON.parse(text), raw_text: text };
  } catch (e) {
    return { ok: false, error: 'invalid_json', parsed: null, raw_text: text };
  }
}

function normalizeInt(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

function normalizeConfidence(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  if (n < 0 || n > 1) return null;
  return n;
}

function safeText(v) {
  if (v === undefined || v === null || v === '') return null;
  const s = String(v).trim();
  return s === '' ? null : s;
}

function safeNumber(v) {
  if (v === undefined || v === null || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function safeJson(v) {
  if (v === undefined || v === null) return null;
  return v;
}

function safeBoolean(v) {
  if (v === undefined || v === null || v === '') return null;
  if (typeof v === 'boolean') return v;
  if (typeof v === 'string') {
    const s = v.trim().toLowerCase();
    if (['true', '1', 'yes', 'y'].includes(s)) return true;
    if (['false', '0', 'no', 'n'].includes(s)) return false;
  }
  return null;
}

return items.map((item, index) => {
  const root = item.json || {};
  const ctx = root.context || {};
  const C = root.constants || {};

  const STAGE = C.stage || { judge: 'judge' };
  const DECISION = C.decision_status || {
    classified: 'classified',
    needs_human_review: 'needs_human_review',
    error: 'error',
  };
  const FINAL = C.final_source || { judge: 'judge', system: 'system' };
  const NEXT = C.next_action || { none: 'none', human_review: 'human_review' };
  const ACTOR = C.actor_type || { llm: 'llm' };
  const LOG = C.log_status || { success: 'success', needs_review: 'needs_review', rejected: 'rejected' };
  const THRESHOLDS = C.thresholds || { min_confidence_judge_ok: 0.60 };
  const MODEL = C.model || { judge_actor_name: 'openai/gpt-4.1-mini' };

  const WORKFLOW_VERSION = root.workflow_version || 'stage2_judge_v1';
  const PROMPT_VERSION = root.prompt_version || 'prompt_judge_v1';

  const runId = normalizeInt(ctx.run_id ?? root.run_id);
  const productId = normalizeInt(ctx.product_id ?? root.product_id);
  const productRawId = normalizeInt(ctx.product_raw_id ?? root.product_raw_id);

  const ruleShortlist = Array.isArray(ctx.rule_shortlist_json)
    ? ctx.rule_shortlist_json
    : (Array.isArray(root.shortlist_json) ? root.shortlist_json : []);
  const branchShortlist = Array.isArray(ctx.branch_shortlist_json)
    ? ctx.branch_shortlist_json
    : (Array.isArray(root.branch_shortlist_json) ? root.branch_shortlist_json : []);

  const allowedIds = new Set();
  for (const list of [ruleShortlist, branchShortlist]) {
    for (const c of list) {
      const id = normalizeInt(c.category_id);
      if (id !== null) allowedIds.add(String(id));
    }
  }
  const llmId = normalizeInt(root.llm_category_id);
  const fb2bId = normalizeInt(root.fallback_2b_category_id);
  if (llmId !== null) allowedIds.add(String(llmId));
  if (fb2bId !== null) allowedIds.add(String(fb2bId));

  const rawModelOutput = root.output ?? root.text ?? root.response ?? root.content ?? root.result ?? null;
  const parsedResult = safeParseJson(rawModelOutput);

  let judgeCategoryId = null;
  let judgeConfidence = null;
  let judgeExplanation = null;
  let judgeNeedsReview = null;
  let judgeWinnerSource = null;
  let judgeValidationPassed = false;
  let judgeRejectReason = null;
  let judgeRawJson = safeJson(parsedResult.ok ? parsedResult.parsed : null);
  let judgeRawOutputText = safeText(parsedResult.raw_text);

  const validWinnerSources = new Set(['llm', 'fallback_2b', 'none']);

  if (!parsedResult.ok) {
    judgeRejectReason = parsedResult.error;
  } else {
    const parsed = parsedResult.parsed || {};
    judgeCategoryId = normalizeInt(parsed.category_id ?? parsed.final_category_id);
    judgeConfidence = normalizeConfidence(parsed.confidence);
    judgeExplanation = safeText(parsed.explanation);
    judgeNeedsReview = safeBoolean(parsed.needs_human_review);
    judgeWinnerSource = safeText(parsed.winner_source);

    if (!judgeExplanation) {
      judgeRejectReason = 'missing_explanation';
    } else if (judgeConfidence === null) {
      judgeRejectReason = 'invalid_confidence';
    } else if (judgeWinnerSource && !validWinnerSources.has(judgeWinnerSource)) {
      judgeRejectReason = 'invalid_winner_source';
    } else if (judgeCategoryId === null && judgeWinnerSource !== 'none') {
      judgeRejectReason = 'null_category';
    } else if (judgeCategoryId !== null && allowedIds.size > 0 && !allowedIds.has(String(judgeCategoryId))) {
      judgeRejectReason = 'category_outside_candidates';
    } else {
      judgeValidationPassed = true;
    }
  }

  let decisionStatus = DECISION.needs_human_review;
  let finalSource = FINAL.system;
  let finalCategoryId = null;
  let finalConfidence = null;
  let finalExplanation = null;
  let nextAction = NEXT.human_review;
  let logStatus = LOG.needs_review;

  if (!judgeValidationPassed) {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = LOG.rejected;
  } else if (judgeNeedsReview === true) {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = LOG.needs_review;
  } else if (judgeCategoryId === null || judgeWinnerSource === 'none') {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = LOG.needs_review;
  } else if (judgeConfidence > THRESHOLDS.min_confidence_judge_ok) {
    decisionStatus = DECISION.classified;
    finalSource = FINAL.judge;
    finalCategoryId = judgeCategoryId;
    finalConfidence = judgeConfidence;
    finalExplanation = judgeExplanation;
    nextAction = NEXT.none;
    logStatus = LOG.success;
  } else {
    decisionStatus = DECISION.needs_human_review;
    nextAction = NEXT.human_review;
    logStatus = LOG.needs_review;
  }

  const routingHint = {
    stage: STAGE.judge,
    judge_validation_passed: judgeValidationPassed,
    judge_confidence: judgeConfidence,
    judge_reject_reason: judgeRejectReason,
    judge_winner_source: judgeWinnerSource,
    judge_needs_review: judgeNeedsReview,
    allowed_candidate_count: allowedIds.size,
    suggested_next_action: nextAction,
  };

  const productClassificationUpdate = {
    product_id: productId,
    product_raw_id: productRawId,
    latest_run_id: runId,
    workflow_version: WORKFLOW_VERSION,
    prompt_version: PROMPT_VERSION,
    rule_top_category_id: safeNumber(root.rule_top_category_id),
    rule_top_score: safeNumber(root.rule_top_score),
    rule_shortlist_id: safeNumber(root.rule_shortlist_id),
    rule_decision_status: safeText(root.rule_decision_status),
    llm_category_id: safeNumber(root.llm_category_id),
    llm_confidence: safeNumber(root.llm_confidence),
    llm_explanation: safeText(root.llm_explanation),
    llm_needs_review: root.llm_needs_review ?? null,
    llm_validation_passed: root.llm_validation_passed ?? null,
    llm_reject_reason: safeText(root.llm_reject_reason),
    llm_raw_json: safeJson(root.llm_raw_json),
    judge_category_id: judgeCategoryId,
    judge_confidence: judgeConfidence,
    judge_explanation: judgeExplanation,
    judge_needs_review: judgeNeedsReview,
    judge_raw_json: judgeRawJson,
    fallback_2a_direction: safeText(root.fallback_2a_direction),
    fallback_2a_block_family: safeText(root.fallback_2a_block_family),
    fallback_2a_family_code: safeText(root.fallback_2a_family_code),
    fallback_2a_nosology_hint: safeText(root.fallback_2a_nosology_hint),
    fallback_2a_confidence: safeNumber(root.fallback_2a_confidence),
    fallback_2a_explanation: safeText(root.fallback_2a_explanation),
    fallback_2a_raw_json: safeJson(root.fallback_2a_raw_json),
    fallback_2b_category_id: safeNumber(root.fallback_2b_category_id),
    fallback_2b_confidence: safeNumber(root.fallback_2b_confidence),
    fallback_2b_explanation: safeText(root.fallback_2b_explanation),
    fallback_2b_raw_json: safeJson(root.fallback_2b_raw_json),
    final_category_id: finalCategoryId,
    final_confidence: finalConfidence,
    final_explanation: finalExplanation,
    final_source: finalSource,
    decision_status: decisionStatus,
    next_action: nextAction,
    routing_hint: routingHint,
  };

  return {
    json: {
      ...root,
      run_id: runId,
      product_id: productId,
      product_raw_id: productRawId,
      stage: STAGE.judge,
      actor_type: ACTOR.llm,
      actor_name: MODEL.judge_actor_name,
      workflow_version: WORKFLOW_VERSION,
      prompt_version: PROMPT_VERSION,
      judge_category_id: judgeCategoryId,
      judge_confidence: judgeConfidence,
      judge_explanation: judgeExplanation,
      judge_needs_review: judgeNeedsReview,
      judge_winner_source: judgeWinnerSource,
      judge_validation_passed: judgeValidationPassed,
      judge_reject_reason: judgeRejectReason,
      judge_raw_json: judgeRawJson,
      judge_raw_output_text: judgeRawOutputText,
      validation_passed: judgeValidationPassed,
      error_message: judgeRejectReason,
      decision_status: decisionStatus,
      next_action: nextAction,
      final_source: finalSource,
      final_category_id: finalCategoryId,
      final_confidence: finalConfidence,
      final_explanation: finalExplanation,
      routing_hint: routingHint,
      product_classification_update: productClassificationUpdate,
    },
    pairedItem: index,
  };
});
